export async function POST(req: Request) {
  try {
    // Authenticate the caller before trusting any body field.
    const { createServerClient } = await import('@supabase/ssr');
    const { cookies } = await import('next/headers');
    const cookieStore = cookies();
    const authClient = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      { cookies: { get: (name) => cookieStore.get(name)?.value } },
    );
    const { data: { session } } = await authClient.auth.getSession();
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }
    const authenticatedUserId = session.user.id;

    const body = await req.json();
    const { type, title, avatarName, role, userId } = body;

    // Reject if caller attempts to impersonate a different user.
    if (userId && userId !== authenticatedUserId) {
      return NextResponse.json({ error: 'Forbidden' }, { status: 403 });
    }

    console.log('[Sara CreateProject] called:', { type, userId: authenticatedUserId, hasServiceKey: !!SERVICE_ROLE_KEY });

    if (!type) {
      return NextResponse.json({ error: 'type is required' }, { status: 400 });
    }

